import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getAllRFQs } from "../api/axios";

const statusBadge = (status) => {
  if (status === "active") {
    return <span className="rounded-full bg-green-100 px-3 py-1 text-xs font-semibold text-[#16a34a]">Active</span>;
  }
  if (status === "force_closed") {
    return <span className="rounded-full bg-red-100 px-3 py-1 text-xs font-semibold text-[#dc2626]">Force Closed</span>;
  }
  return <span className="rounded-full bg-gray-200 px-3 py-1 text-xs font-semibold text-gray-700">Closed</span>;
};

const formatDateTime = (dt) => {
  if (!dt) return "";
  const d = new Date(dt);
  return d.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
};

const AuctionList = () => {
  const navigate = useNavigate();
  const [rfqs, setRfqs] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchRFQs = async () => {
    setLoading(true);
    try {
      const data = await getAllRFQs();
      setRfqs(data);
    } catch (e) {
      setRfqs([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRFQs();
    const interval = setInterval(fetchRFQs, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen bg-[#f1f5f9] px-4 py-8 sm:px-6 lg:px-8">
      <div className="mx-auto max-w-7xl">
        <div className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <h1 className="text-2xl font-bold text-gray-900 sm:text-3xl">RFQ Auctions</h1>
          <button
            className="rounded-md bg-[#1e3a5f] px-5 py-2.5 text-sm font-semibold text-white shadow hover:bg-slate-800"
            onClick={() => navigate("/create-rfq")}
          >
            Create New RFQ
          </button>
        </div>

        <div className="rounded-xl bg-white shadow-lg">
          {loading ? (
            <div className="p-10 text-center text-gray-500">Loading auctions...</div>
          ) : rfqs.length === 0 ? (
            <div className="flex flex-col items-center justify-center gap-3 p-12 text-center text-gray-500">
              <svg className="h-10 w-10 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.8} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5" />
              </svg>
              <p className="text-lg font-medium">No auctions yet</p>
            </div>
          ) : (
            <div className="overflow-x-auto rounded-xl">
              <table className="min-w-full border-collapse">
                <thead>
                  <tr className="bg-[#1e3a5f] text-left text-sm text-white">
                    <th className="px-4 py-3 font-semibold">RFQ Name</th>
                    <th className="px-4 py-3 font-semibold">Reference ID</th>
                    <th className="px-4 py-3 font-semibold">Current Lowest Bid</th>
                    <th className="px-4 py-3 font-semibold">Current Bid Close Time</th>
                    <th className="px-4 py-3 font-semibold">Forced Close Time</th>
                    <th className="px-4 py-3 font-semibold">Status</th>
                    <th className="px-4 py-3 font-semibold">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {rfqs.map((rfq) => (
                    <tr key={rfq.id} className="border-b border-gray-200 text-sm text-gray-800 hover:bg-gray-50">
                      <td className="px-4 py-3 font-medium">{rfq.name}</td>
                      <td className="px-4 py-3">{rfq.reference_id}</td>
                      <td className="px-4 py-3">
                        {rfq.lowest_bid == null ? (
                          <span className="text-gray-400">No bids yet</span>
                        ) : (
                          <span className="font-bold text-[#16a34a]">£{rfq.lowest_bid.toFixed(2)}</span>
                        )}
                      </td>
                      <td className="px-4 py-3">{formatDateTime(rfq.bid_close_time)}</td>
                      <td className="px-4 py-3">{formatDateTime(rfq.forced_close_time)}</td>
                      <td className="px-4 py-3">{statusBadge(rfq.status)}</td>
                      <td className="px-4 py-3">
                        <button
                          className="rounded-md bg-[#2563eb] px-3 py-1.5 text-xs font-semibold text-white hover:bg-blue-700"
                          onClick={() => navigate(`/rfq/${rfq.id}`)}
                        >
                          View Details
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AuctionList;
